  ('pukao-1fb53453-moex-00416', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-d1a761c9', 'sub-pukao-1fb53453-02', NULL, 'single_choice', '甲之三合院古厝，長期出租他人作為廠房使用。嗣主管機關依法將其列為暫定古蹟，但因承租人之營 運可能破壞古蹟，致甲不得繼續出租。甲得基於下列何者，請求主管機關彌補其租金收益損失？', '["公法上不當得利返還請求權", "損失補償請求權", "國家賠償請求權", "公法上無因管理之管理費用請求權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL)
